// Dashboard Handler - Stats, Aggregations
import { success, error } from "../utils/response.js";
import { buildOrderFilters, buildWhereClause } from "../utils/db.js";

export async function handleDashboard(request, env, url) {
  try {
    const period = url.searchParams.get("period") || "all";

    // Build date filter based on period
    let dateFilter = "";
    let dateParam = null;
    const now = new Date();

    if (period === "today") {
      const today = now.toISOString().slice(0, 10);
      dateFilter = " WHERE created_at >= ?";
      dateParam = today;
    } else if (period === "week") {
      const weekAgo = new Date(now);
      weekAgo.setDate(weekAgo.getDate() - 7);
      dateFilter = " WHERE created_at >= ?";
      dateParam = weekAgo.toISOString();
    } else if (period === "month") {
      const monthAgo = new Date(now);
      monthAgo.setMonth(monthAgo.getMonth() - 1);
      dateFilter = " WHERE created_at >= ?";
      dateParam = monthAgo.toISOString();
    }

    // Run all dashboard queries in parallel
    const queries = [];

    // Total orders count
    if (dateParam) {
      queries.push(env.DB.prepare("SELECT COUNT(*) as total FROM orders" + dateFilter).bind(dateParam).first());
    } else {
      queries.push(env.DB.prepare("SELECT COUNT(*) as total FROM orders").first());
    }

    // Total revenue (paid and delivered orders)
    if (dateParam) {
      queries.push(
        env.DB.prepare("SELECT COALESCE(SUM(amount), 0) as revenue FROM orders WHERE payment_method = 'prepaid' AND status IN ('confirmed','delivered','shipped') AND created_at >= ?")
          .bind(dateParam).first()
      );
    } else {
      queries.push(
        env.DB.prepare("SELECT COALESCE(SUM(amount), 0) as revenue FROM orders WHERE payment_method = 'prepaid' AND status IN ('confirmed','delivered','shipped')").first()
      );
    }

    // Status counts (single GROUP BY query)
    let statusQuery = "SELECT status, COUNT(*) as count FROM orders";
    let statusParams = [];
    if (dateParam) {
      statusQuery += " WHERE created_at >= ?";
      statusParams.push(dateParam);
    }
    statusQuery += " GROUP BY status";
    queries.push(
      env.DB.prepare(statusQuery).bind(...statusParams).all()
    );
    // Also get total count for the period
    if (dateParam) {
      queries.push(env.DB.prepare("SELECT COUNT(*) as total FROM orders" + dateFilter).bind(dateParam).first());
    } else {
      queries.push(env.DB.prepare("SELECT COUNT(*) as total FROM orders").first());
    }

    // Today's orders count (always included)
    const today = now.toISOString().slice(0, 10);
    queries.push(
      env.DB.prepare("SELECT COUNT(*) as count FROM orders WHERE created_at >= ?").bind(today).first()
    );

    // Run all queries
    const results = await Promise.all(queries);

    const totalOrders = results[0]?.total || 0;
    const totalRevenue = results[1]?.revenue || 0;

    // Parse GROUP BY results
    const statusCounts = {};
    const statusRows = results[2]?.results || [];
    for (const row of statusRows) {
      statusCounts[row.status] = row.count;
    }

    // Ensure all expected statuses exist
    const statuses = ["pending", "confirmed", "shipped", "delivered", "cancelled"];
    for (const s of statuses) {
      if (!statusCounts[s]) statusCounts[s] = 0;
    }

    const todayOrders = results[4]?.count || 0;

    return success({
      period,
      totalOrders,
      totalRevenue,
      todayOrders,
      statusCounts,
      pendingOrders: statusCounts.pending || 0
    });
  } catch (err) {
    console.error("Dashboard error:", err);
    return error("Failed to fetch dashboard data", 500);
  }
}
